import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";
import Layout from "../components/Layout";
import { StatusPieChart, AssetTypeBarChart } from "../components/DashboardChart";
import { useAuth } from "../context/AuthContext";

const API = "http://localhost:8080";

// ── Small stat card ───────────────────────────────────────────────
function KpiCard({ icon, label, value, sub, color, bg, topColor, onClick, badge }) {
  return (
    <div
      onClick={onClick}
      style={{
        background:"#fff", borderRadius:12,
        border:`1px solid ${color}22`,
        borderTop:`3px solid ${topColor||color}`,
        padding:"18px 20px",
        boxShadow:"0 1px 3px rgba(0,0,0,0.04),0 4px 12px rgba(0,0,0,0.04)",
        cursor:onClick?"pointer":"default",
        transition:"all 0.18s",
        position:"relative",
      }}
      onMouseEnter={(e)=>{ if(onClick) e.currentTarget.style.transform="translateY(-2px)"; }}
      onMouseLeave={(e)=>{ e.currentTarget.style.transform="translateY(0)"; }}
    >
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
        <div style={{width:42,height:42,borderRadius:10,background:bg,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>
          {icon}
        </div>
        {badge&&<span style={{padding:"2px 8px",borderRadius:20,background:bg,color:color,fontSize:11,fontWeight:700}}>{badge}</span>}
      </div>
      <div style={{fontSize:30,fontWeight:800,color,lineHeight:1,letterSpacing:"-0.5px",marginBottom:6}}>
        {value}
      </div>
      <div style={{fontSize:12.5,fontWeight:700,color:"var(--gray-700)",marginBottom:2}}>{label}</div>
      <div style={{fontSize:11.5,color:"var(--gray-400)"}}>{sub}</div>
    </div>
  );
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [dashboard, setDashboard] = useState({ totalAssets:null,availableAssets:null,assignedAssets:null,totalEmployees:null });
  const [pendingRequests, setPendingRequests] = useState(null);
  const [assets, setAssets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const now = new Date();
  const greeting = now.getHours()<12?"Good morning":now.getHours()<17?"Good afternoon":"Good evening";

  useEffect(()=>{
    setLoading(true);
    Promise.all([
      axios.get(`${API}/assets/dashboard`),
      axios.get(`${API}/assets`),
      axios.get(`${API}/api/admin/requests`),
    ])
    .then(([dashRes,assetsRes,reqRes])=>{
      setDashboard(dashRes.data);
      setAssets(assetsRes.data);
      setPendingRequests((reqRes.data||[]).filter((r)=>r.status==="PENDING").length);
      setError("");
    })
    .catch(()=>setError("Couldn't reach the API. Is the Spring Boot server running on :8080?"))
    .finally(()=>setLoading(false));
  },[]);

  // Derived counts from live assets list
  const derivedCounts = useMemo(()=>({
    spare:       assets.filter((a)=>a.assetStatus==="Spare").length,
    underRepair: assets.filter((a)=>a.assetStatus==="Under Repair").length,
    faulty:      assets.filter((a)=>a.assetStatus==="Faulty").length,
  }),[assets]);

  const pieData = useMemo(()=>[
    {name:"Available",value:dashboard.availableAssets||0},
    {name:"Assigned", value:dashboard.assignedAssets||0},
    {name:"Spare",    value:derivedCounts.spare},
    {name:"Repair",   value:derivedCounts.underRepair},
    {name:"Faulty",   value:derivedCounts.faulty},
  ],[dashboard,derivedCounts]);

  const typeData = useMemo(()=>{
    const counts={};
    assets.forEach((a)=>{const t=a.assetType||"Other";counts[t]=(counts[t]||0)+1;});
    return Object.entries(counts).map(([name,value])=>({name,value}));
  },[assets]);

  const recentActivity = useMemo(()=>{
    const events=[];
    assets.forEach((a)=>{
      if(a.assignedDate) events.push({id:`assign-${a.assetId}`,icon:"💻",iconBg:"#eff6ff",action:"Asset Assigned",detail:`${a.laptopName||a.assetType} assigned to ${a.employeeName||"an employee"}`,date:a.assignedDate});
      if(a.returnedStatus==="Yes"&&a.returnDate) events.push({id:`return-${a.assetId}`,icon:"↩️",iconBg:"#ecfdf5",action:"Asset Returned",detail:`${a.laptopName||a.assetType} returned`,date:a.returnDate});
    });
    return events.filter((e)=>e.date).sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,6);
  },[assets]);

  const utilizationRate = dashboard.totalAssets?Math.round((dashboard.assignedAssets/dashboard.totalAssets)*100):0;

  const V = (v) => loading?"—":(v??0);

  return (
    <Layout title="Dashboard" subtitle="Live overview of your IT inventory">
      {error&&(
        <div style={{marginBottom:20,borderRadius:10,padding:"12px 18px",background:"#fef2f2",border:"1px solid #fecaca",fontSize:13,color:"#991b1b",display:"flex",gap:8,alignItems:"center"}}>
          ⚠️ {error}
        </div>
      )}

      {/* Welcome Banner */}
      <div className="welcome-banner" style={{marginBottom:24}}>
        <div className="welcome-banner-text">
          <div className="welcome-banner-greeting">{greeting},</div>
          <div className="welcome-banner-title">{user?.name||"Administrator"} 👋</div>
          <div className="welcome-banner-sub">
            {loading?"Loading inventory…":`${dashboard.availableAssets??0} assets ready to assign · ${pendingRequests??0} pending requests`}
          </div>
        </div>
        <div className="welcome-banner-icon">🖥️</div>
      </div>

      {/* 6-Card KPI Grid */}
      <div className="kpi-row kpi-row-6" style={{marginBottom:24}}>
        <KpiCard
          icon="📦" label="Total Assets" value={V(dashboard.totalAssets)} sub="Across all departments & locations"
          color="#1a56db" bg="#eff6ff" topColor="#1a56db"
        />
        <KpiCard
          icon="✅" label="Available" value={V(dashboard.availableAssets)} sub="Ready to be assigned"
          color="#16a34a" bg="#dcfce7" topColor="#16a34a"
        />
        <KpiCard
          icon="🔗" label="Assigned" value={V(dashboard.assignedAssets)} sub="Currently in active use"
          color="#1d4ed8" bg="#dbeafe" topColor="#1d4ed8"
          badge={utilizationRate>0?`${utilizationRate}% utilized`:undefined}
        />
        <KpiCard
          icon="🗃️" label="Spare" value={V(derivedCounts.spare)} sub="In reserve, unassigned"
          color="#a16207" bg="#fef9c3" topColor="#a16207"
        />
        <KpiCard
          icon="🔧" label="Under Repair" value={V(derivedCounts.underRepair)} sub="Sent for servicing"
          color="#c2410c" bg="#ffedd5" topColor="#c2410c"
        />
        <KpiCard
          icon="⚠️" label="Faulty" value={V(derivedCounts.faulty)} sub="Flagged as defective"
          color="#b91c1c" bg="#fee2e2" topColor="#b91c1c"
        />
      </div>

      {/* Second row: Employees + Pending Requests */}
      <div className="kpi-row kpi-row-2" style={{marginBottom:24}}>
        <KpiCard
          icon="👥" label="Total Employees" value={V(dashboard.totalEmployees)} sub="Active employee directory"
          color="#7c3aed" bg="#f5f3ff" topColor="#7c3aed"
        />
        <KpiCard
          icon="📋" label="Pending Requests" value={V(pendingRequests)} sub="Employee requests awaiting review"
          color="#dc2626" bg="#fef2f2" topColor="#dc2626"
          badge={pendingRequests>0?"Action needed":undefined}
          onClick={()=>navigate("/asset-requests")}
        />
      </div>

      {/* Charts Row */}
      <div className="grid-2-1" style={{marginBottom:24}}>
        <div className="card">
          <div className="card-header">
            <div>
              <div className="card-title">Assets by Type</div>
              <div className="card-subtitle">Live breakdown of your current inventory</div>
            </div>
          </div>
          <div className="card-body"><AssetTypeBarChart data={typeData}/></div>
        </div>
        <div className="card">
          <div className="card-header">
            <div>
              <div className="card-title">Status Allocation</div>
              <div className="card-subtitle">Inventory by status</div>
            </div>
          </div>
          <div className="card-body"><StatusPieChart data={pieData}/></div>
        </div>
      </div>

      {/* Bottom Row */}
      <div className="grid-2">
        <div className="card">
          <div className="card-header">
            <div>
              <div className="card-title">Recent Activity</div>
              <div className="card-subtitle">Latest asset events from your org</div>
            </div>
            <button className="btn btn-secondary btn-sm" onClick={()=>navigate("/assets")}>View All</button>
          </div>
          <div className="card-body" style={{padding:"8px 22px"}}>
            {recentActivity.length===0?(
              <div className="empty-state" style={{padding:"28px 0"}}>
                <div className="empty-title">No activity yet</div>
                <div className="empty-sub">Assign or return an asset to see it appear here.</div>
              </div>
            ):(
              recentActivity.map((item)=>(
                <div key={item.id} className="activity-item">
                  <div className="activity-icon" style={{background:item.iconBg}}>{item.icon}</div>
                  <div className="activity-text">
                    <div className="activity-main"><strong>{item.action}</strong> — {item.detail}</div>
                    <div className="activity-meta">{item.date}</div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          <div className="card">
            <div className="card-header"><div className="card-title">Quick Actions</div></div>
            <div className="card-body">
              <div className="action-grid">
                {[
                  {label:"Add Asset",icon:"➕",color:"#1a56db",bg:"#eff6ff",link:"/assets"},
                  {label:"View Assets",icon:"📋",color:"#059669",bg:"#ecfdf5",link:"/assets"},
                  {label:"Employees",icon:"👥",color:"#7c3aed",bg:"#f5f3ff",link:"/employees"},
                  {label:"Requests",icon:"🔔",color:"#d97706",bg:"#fffbeb",link:"/asset-requests"},
                ].map((q)=>(
                  <Link key={q.label} to={q.link} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:8,padding:"16px 12px",borderRadius:10,background:q.bg,border:`1.5px solid ${q.color}20`,cursor:"pointer",textDecoration:"none",transition:"all 0.15s"}}
                    onMouseEnter={(e)=>{e.currentTarget.style.transform="translateY(-1px)";}}
                    onMouseLeave={(e)=>{e.currentTarget.style.transform="translateY(0)";}}
                  >
                    <span style={{fontSize:22}}>{q.icon}</span>
                    <span style={{fontSize:12,fontWeight:600,color:q.color}}>{q.label}</span>
                  </Link>
                ))}
              </div>
            </div>
          </div>

          <div className="card">
            <div className="card-header"><div className="card-title">Inventory Health</div></div>
            <div className="card-body" style={{padding:"16px 22px",display:"flex",flexDirection:"column",gap:14}}>
              {[
                {label:"Utilization",value:utilizationRate,color:"#1a56db"},
                {label:"Availability",value:dashboard.totalAssets?Math.round((dashboard.availableAssets/dashboard.totalAssets)*100):0,color:"#16a34a"},
              ].map((m)=>(
                <div key={m.label}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
                    <span style={{fontSize:12.5,fontWeight:600,color:"#475569"}}>{m.label}</span>
                    <span style={{fontSize:12.5,fontWeight:700,color:m.color}}>{m.value}%</span>
                  </div>
                  <div style={{height:6,background:"#f1f5f9",borderRadius:10}}>
                    <div style={{height:"100%",borderRadius:10,background:m.color,width:`${m.value}%`,transition:"width 1s ease"}}/>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
}
