import React, { useEffect, useState } from "react";
import Sidebar from "./Sidebar";
import NotificationBell from "./NotificationBell";
import { useAuth } from "../context/AuthContext";
import { useLocation } from "react-router-dom";

function initials(name) {
  return (name || "U").split(" ").map((w) => w[0]).join("").toUpperCase().slice(0, 2);
}
function avatarBg(name) {
  const colors = ["#1a56db","#059669","#7c3aed","#b45309","#be185d"];
  return colors[(name || "A").charCodeAt(0) % colors.length];
}

export default function Layout({ title, subtitle, children, actions }) {
  const { user } = useAuth();
  const isAdmin  = user?.role === "admin";
  const location = useLocation();
  const [mobileNavOpen, setMobileNavOpen] = useState(false);

  // Close the mobile drawer automatically whenever the route changes
  useEffect(() => { setMobileNavOpen(false); }, [location.pathname]);

  const now = new Date();
  const greeting =
    now.getHours() < 12 ? "Good morning" :
    now.getHours() < 17 ? "Good afternoon" : "Good evening";

  return (
    <div className="app-shell">
      <a href="#main-content" className="skip-link">Skip to main content</a>
      <Sidebar open={mobileNavOpen} onClose={() => setMobileNavOpen(false)} />
      <div className="app-main">
        <header className="topbar">
          <button
            className="menu-toggle-btn"
            onClick={() => setMobileNavOpen((v) => !v)}
            aria-label={mobileNavOpen ? "Close navigation menu" : "Open navigation menu"}
            aria-expanded={mobileNavOpen}
          >
            {mobileNavOpen ? "✕" : "☰"}
          </button>
          <div className="topbar-title">
            <div className="topbar-page">{title}</div>
            {subtitle && <div className="topbar-sub">{subtitle}</div>}
          </div>
          <div className="topbar-actions">
            {/* Real notification bell for admins; static icon for employees */}
            {isAdmin
              ? <NotificationBell />
              : (
                <button className="topbar-btn" title="Notifications" style={{ fontSize: 18 }}>
                  🔔
                </button>
              )
            }
            <button className="topbar-btn" title="Help" style={{ fontSize: 18 }}>❓</button>
            <div
              className="topbar-avatar"
              title={`${greeting}, ${user?.name}`}
              style={{ background: avatarBg(user?.name) }}
            >
              {initials(user?.name)}
            </div>
          </div>
        </header>

        <main id="main-content" className="page-content fade-in">
          {actions && (
            <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 20, flexWrap: "wrap", gap: 8 }}>
              {actions}
            </div>
          )}
          {children}
        </main>
      </div>
    </div>
  );
}
